SELECT ts_pivot.state, date_trunc('month', date_add('second', -900, ts_pivot.timestamp)) AS timestamp, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(coalesce(ts_pivot.up__elec_minus_gas, ts_pivot.bs__elec_minus_gas) * bs.weight) AS elec_minus_gas FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp AS timestamp, resstock_2024_amy2018_release_2_by_state_vu.state AS state, sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0) THEN resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" - resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" ELSE NULL END) AS bs__elec_minus_gas, sum(CASE WHEN (resstock_2024_amy2018_release_2_by_state_vu.upgrade = 1) THEN resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" - resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" ELSE NULL END) AS up__elec_minus_gas FROM resstock_2024_amy2018_release_2_by_state_vu WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade IN (0, 1) AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' GROUP BY resstock_2024_amy2018_release_2_by_state_vu.bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp, resstock_2024_amy2018_release_2_by_state_vu.state) AS ts_pivot JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = ts_pivot.bldg_id AND bs.upgrade = 0 GROUP BY 1, 2 ORDER BY 1, 2